class Solution {
    public int minStable(int[] nums, int maxC) {
        int n = nums.length;
        int[] gcd = new int[n];
        gcd[0] = nums[0];
        for (int i = 1; i < n; i++) {
            gcd[i] = getGcd(gcd[i - 1], nums[i]);
        }

        int res = 0;
        int left = 0;
        int count = 0;
        for (int right = 0; right < n; right++) {
            if (nums[right] < 2) count++;
            while (count > maxC) {
                if (nums[left] < 2) count--;
                left++;
            }
            if (gcd[right] >= 2) {
                res = Math.max(res, right - left + 1);
            } else {
                int currGcd = nums[right];
                int tempLeft = right;
                for (int i = right - 1; i >= left; i--) {
                    currGcd = getGcd(currGcd, nums[i]);
                    if (currGcd >= 2) {
                        res = Math.max(res, tempLeft - i + 1);
                        tempLeft = i;
                    }
                }
            }
        }
        return res == 0 ? 0 : n - res;
    }

    private int getGcd(int a, int b) {
        if (b == 0) return a;
        return getGcd(b, a % b);
    }
}
